INSERT INTO `function_definitions` VALUES ('func-calendar-create-event','system','calendar_create_event','Create Calendar Event','calendar','Create events in Google Calendar or Outlook','{\"type\": \"object\", \"required\": [\"title\", \"start_time\", \"end_time\"], \"properties\": {\"title\": {\"type\": \"string\", \"description\": \"Event title\"}, \"end_time\": {\"type\": \"string\", \"format\": \"date-time\", \"description\": \"End time (ISO 8601)\"}, \"location\": {\"type\": \"string\", \"description\": \"Event location\"}, \"attendees\": {\"type\": \"array\", \"description\": \"List of attendee emails\"}, \"start_time\": {\"type\": \"string\", \"format\": \"date-time\", \"description\": \"Start time (ISO 8601)\"}, \"description\": {\"type\": \"string\", \"description\": \"Event description\"}, \"reminder_minutes\": {\"type\": \"integer\", \"default\": 15, \"description\": \"Reminder before event\"}}}','{\"link\": \"https://calendar.google.com/event?eid=123\", \"event_id\": \"evt_123\", \"_metadata\": {\"source\": \"mock\"}}','https://www.googleapis.com/calendar/v3/calendars/primary/events','POST','{\"Content-Type\": \"application/json\", \"Authorization\": \"Bearer {{googleCalendarToken}}\"}','{}',1,1,'2025-08-05 01:06:27','2025-08-05 01:06:27','[\"googleCalendarToken\"]','{\"googleCalendarToken\": {\"required\": true, \"description\": \"Google Calendar API token\"}}',NULL,'default','{\"error\": \"Calendar access denied\", \"event_id\": null, \"_metadata\": {\"source\": \"fallback\"}}'),('func-csv-parse','system','csv_parse','Parse CSV Data','data_transform','Parse CSV content into structured JSON data','{\"type\": \"object\", \"required\": [\"csv_content\"], \"properties\": {\"encoding\": {\"type\": \"string\", \"default\": \"utf-8\", \"description\": \"Text encoding\"}, \"delimiter\": {\"type\": \"string\", \"default\": \",\", \"description\": \"CSV delimiter\"}, \"has_header\": {\"type\": \"boolean\", \"default\": true, \"description\": \"First row contains