name\": {\"type\": \"string\", \"description\": \"Specific sheet to parse\"}, \"file_content\": {\"type\": \"string\", \"description\": \"Base64 encoded Excel file\"}}}','{\"data\": [{\"col1\": \"value1\"}], \"sheets\": [\"Sheet1\"], \"_metadata\": {\"source\": \"mock\"}, \"total_rows\": 100}',NULL,NULL,'{}','{}',1,1,'2025-08-05 01:06:32','2025-08-05 01:06:32','[]','{}',NULL,'default','{\"data\": [], \"error\": \"Excel parsing failed\", \"_metadata\": {\"source\": \"fallback\"}}'),('func-file-upload','system','file_upload','Upload File','files','Upload files to cloud storage (AWS S3, Google Drive, etc.)','{\"type\": \"object\", \"required\": [\"file_content\", \"filename\", \"bucket\"], \"properties\": {\"bucket\": {\"type\": \"string\", \"description\": \"Storage bucket/folder\"}, \"public\": {\"type\": \"boolean\", \"default\": false, \"description\": \"Make file publicly accessible\"}, \"filename\": {\"type\": \"string\", \"description\": \"Name of the file\"}, \"content_type\": {\"type\": \"string\", \"description\": \"MIME type of the file\"}, \"file_content\": {\"type\": \"string\", \"description\": \"File content (base64 encoded)\"}}}','{\"file_id\": \"abc123\", \"file_url\": \"https://storage.example.com/file.pdf\", \"_metadata\": {\"source\": \"mock\"}}','https://s3.amazonaws.com','PUT','{\"Content-Type\": \"{{content_type}}\", \"Authorization\": \"AWS4-HMAC-SHA256 {{awsCredentials}}\"}','{}',1,1,'2025-08-05 01:06:27','2025-08-05 01:06:27','[\"awsAccessKey\", \"awsSecretKey\"]','{\"awsAccessKey\": {\"required\": true}, \"awsSecretKey\": {\"required\": true}}',NULL,'default','{\"error\": \"Upload failed\", \"file_url\": null, \"_metadata\": {\"source\": \"fallback\"}}'),('func-openweather-current','system','get_current_weather','Get Current Weather','weather','Get current weather information for a specific location using OpenWeather API','{\"type\": \"object\", \"required\": [\"location\"], \"properties\": {\"lang\": {\"type\": \"string\", \"description\": \"Language code for weather description (e.g., en, es, fr)\"}, \"units\": {\"enum\": [\"metric\", \"imperial\", \"kelvin\"], \"type\": \"string\", \"description\": \"Units of measurement. metric: Celsius, imperial: Fahrenheit, kelvin: Kelvin\"}, \"location\": {\"type\": \"string\", \"description\": \"City name, state code (US only), and country code (ISO 3166) separated by comma. Format: \\\"City,State,Country\\\" or \\\"City,Country\\\"\"}}}','{\"dt\": 1560350645, \"id\": 420006353, \"cod\": 200, \"sys\": {\"id\": 5122, \"type\": 1, \"sunset\": 1560396563, \"country\": \"US\", \"sunrise\": 1560343627}, \"base\": \"stations\", \"main\": {\"temp\": 282.55, \"humidity\": 100, \"pressure\": 1023, \"temp_max\": 284.26, \"temp_min\": 280.37, \"feels_like\": 281.86}, \"name\": \"Mountain View\", \"wind\": {\"deg\": 350, \"speed\": 1.5}, \"coord\": {\"lat\": 37.39, \"lon\": -122.08}, \"clouds\": {\"all\": 1}, \"weather\": [{\"id\": 800, \"icon\": \"01d\", \"main\": \"Clear\", \"description\": \"clear sky\"}], \"timezone\": -25200, \"visibility\": 10000}','https://api.openweathermap.org/data/2.5/weather','GET','{\"Accept\": \"application/json\"}','{}',1,1,'2025-08-05 00:53:47','2025-08-05 00:53:47','[\"openWeatherApiKey\"]','{\"openWeatherApiKey\": {\"required\": true, \"description\": \"OpenWeather API key from openweathermap.org\"}}',NULL,'default','{\"dt\": 1560350645, \"id\": 420006353, \"cod\": 200, \"sys\": {\"id\": 5122, \"type\": 1, \"sunset\": 1560396563, \"country\": \"US\", \"sunrise\": 1560343627}, \"base\": \"stations\", \"main\": {\"temp\": 282.55, \"humidity\": 100, \"pressure\": 1023, \"temp_max\": 284.26, \"temp_min\": 280.37, \"feels_like\": 281.86}, \"name\": \"Mountain View\", \"wind\": {\"deg\": 350, \"speed\": 1.5}, \"coord\": {\"lat\": 37.39, \"lon\": -122.08}, \"clouds\": {\"all\": 1}, \"weather\": [{\"id\": 800, \"icon\": \"01d\", \"main\": \"Clear\", \"description\": \"clear sky\"}], \"timezone\": -25200, \"_metadata\": {\"error\": \"OpenWeather API unavailable, showing mock data for Mountain View, CA\", \"source\": \"fallback\"}, \"visibility\": 10000}'),('func-github-add-comment','system','github_add_comment','GitHub Add Comment','github','Add a comment to a GitHub issue or pull request. Perfect for AI agents to provide analysis, updates, or additional information to ongoing discussions.','{\"type\": \"object\", \"required\": [\"owner\", \"repo\", \"issue_number\", \"body\"], \"properties\": {\"body\": {\"type\": \"string\", \"description\": \"The comment content. Supports full GitHub Markdown formatting including code blocks, tables, and links.\"}, \"repo\": {\"type\": \"string\", \"description\": \"Repository name (e.g., \\\"vscode\\\", \\\"react\\\", \\\"agentlog\\\")\"}, \"owner\": {\"type\": \"string\", \"description\": \"GitHub username or organization name (e.g., \\\"microsoft\\\", \\\"facebook\\\", \\\"google\\\")\"}, \"reaction\": {\"enum\": [\"+1\", \"-1\", \"laugh\", \"hooray\", \"confused\", \"heart\", \"rocket\", \"eyes\"], \"type\": \"string\", \"examples\": [\"rocket\", \"eyes\", \"+1\"], \"description\": \"Optional reaction to add to your own comment\"}, \"issue_number\": {\"type\": \"integer\", \"minimum\": 1, \"description\": \"The issue or pull request number to comment on\"}}}','{\"id\": 987654321, \"url\": \"https://api.github.com/repos/owner/repo/issues/comments/987654321\", \"body\": \"I analyzed the code and found the issue is in the authentication logic.\", \"user\": {\"id\": 12345, \"type\": \"User\", \"login\": \"gogent-ai\", \"avatar_url\": \"https://avatars.githubusercontent.com/u/12345?v=4\"}, \"node_id\": \"IC_abcd1234\", \"html_url\": \"https://github.com/owner/repo/issues/123#issuecomment-987654321\", \"_metadata\": {\"source\": \"mock\", \"comment_type\": \"analysis\"}, \"issue_url\": \"https://api.github.com/repos/owner/repo/issues/123\", \"created_at\": \"2025-01-30T15:45:00Z\", \"updated_at\": \"2025-01-30T15:45:00Z\"}','https://api.github.com/repos/{owner}/{repo}/issues/{issue_number}/comments','POST','{\"Accept\": \"application/vnd.github.v3+json\", \"User-Agent\": \"GoGent-App\", \"Content-Type\": \"application/json\"}','{}',1,1,'2025-08-05 01:05:36','2025-08-05 01:05:36','[\"githubApiKey\"]','{\"githubApiKey\": {\"required\": true, \"description\": \"GitHub API token with repository write access and issues scope\"}}',NULL,'default','{\"id\": 987654321, \"url\": \"https://api.github.com/repos/owner/repo/issues/comments/987654321\", \"body\": \"Comment added successfully but GitHub API is currently unavailable.\", \"html_url\": \"https://github.com/owner/repo/issues/123#issuecomment-987654321\", \"_metadata\": {\"error\": \"GitHub API unavailable - comment not posted\", \"source\": \"fallback\"}, \"created_at\": \"2025-01-30T15:45:00Z\"}'),('func-github-analyze-repository','system','github_analyze_repository','GitHub Analyze Repository','github','Perform comprehensive analysis of a GitHub repository including metadata, statistics, languages used, and overall project insights. Use this first to understand a repository before diving into specific files or issues.','{\"type\": \"object\", \"required\": [\"owner\", \"repo\"], \"properties\": {\"repo\": {\"type\": \"string\", \"description\": \"Repository name (e.g., \\\"vscode\\\", \\\"react\\\", \\\"tensorflow\\\")\"}, \"owner\": {\"type\": \"string\", \"description\": \"GitHub username or organization name (e.g., \\\"microsoft\\\", \\\"facebook\\\", \\\"google\\\")\"}, \"max_files\": {\"type\": \"integer\", \"default\": 50, \"maximum\": 200, \"minimum\": 10, \"description\": \"Maximum number of files to analyze for code structure insights\"}, \"analysis_depth\": {\"enum\": [\"basic\", \"detailed\", \"comprehensive\"], \"type\": \"string\", \"default\": \"basic\", \"description\": \"Level of analysis: \\\"basic\\\" (quick overview), \\\"detailed\\\" (thorough analysis), \\\"comprehensive\\\" (full deep-dive)\"}, \"include_readme\": {\"type\": \"boolean\", \"default\": true, \"description\": \"Whether to include README analysis in the results\"}, \"include_dependencies\": {\"type\": \"boolean\", \"default\": true, \"description\": \"Whether to analyze project dependencies and package files\"}}}','{\"_metadata\": {\"source\": \"mock\", \"analysis_time\": \"2.5s\"}, \"code_analysis\": {\"languages\": {\"CSS\": 25, \"HTML\": 15, \"JavaScript\": 60}, \"structure\": \"Standard web application structure\", \"total_files\": 25}, \"repository_info\": {\"name\": \"sample-repo\", \"forks\": 8, \"stars\": 42, \"language\": \"JavaScript\", \"description\": \"A sample repository\"}}','https://api.github.com/repos/{owner}/{repo}','GET','{\"Accept\": \"application/vnd.github.v3+json\", \"User-Agent\": \"GoGent-App\"}','{}',1,1,'2025-08-05 00:53:48','2025-08-05 01:05:36','[\"githubApiKey\"]','{\"githubApiKey\": {\"required\": true, \"description\": \"GitHub API token\"}}',NULL,'default','{\"_metadata\": {\"error\": \"GitHub API unavailable\", \"source\": \"fallback\", \"analysis_time\": \"0ms\"}, \"code_analysis\": {\"languages\": {\"CSS\": 25, \"HTML\": 15, \"JavaScript\": 60}, \"structure\": \"Standard web application structure\", \"total_files\": 25}, \"repository_info\": {\"name\": \"sample-repo\", \"forks\": 8, \"stars\": 42, \"language\": \"JavaScript\", \"description\": \"A sample repository\"}}'),('func-github-api-key-setup','system','github_api_key_setup','GitHub API Key Setup Guide','github','Provides step-by-step instructions for setting up GitHub API access','{\"type\": \"object\", \"required\": [], \"properties\": {\"step\": {\"enum\": [\"create\", \"configure\", \"test\"], \"type\": \"string\", \"default\": \"create\", \"description\": \"Which setup step to show: \\\"create\\\", \\\"configure\\\", or \\\"test\\\"\"}}}','{\"instructions\": {\"test\": \"Test the API key by calling a simple GitHub API endpoint\", \"create\": \"Go to https://github.com/settings/tokens and create a new Personal Access Token with \\\"repo\\\" scope\", \"configure\": \"Add your GitHub API key to the system configuration\"}, \"troubleshooting\": {\"http_401\": \"API key is invalid or expired\", \"http_403\": \"API key may not have sufficient permissions\", \"http_404\": \"Check if repository exists and is accessible with your API key\"}}','','MOCK','{}','{}',1,1,'2025-08-05 00:53:53','2025-08-05 00:53:53','[]','{}',NULL,'default','{\"setup_required\": true, \"documentation_url\": \"https://docs.github.com/en/authentication/keeping-your-account-and-data-secure/creating-a-personal-access-token\"}'),('76103138-7198-11f0-9aa8-f9c902b06a04','system','github_create_branch','Create GitHub Branch','github','Create a new branch in a GitHub repository from an existing branch, tag, or commit','{\"type\": \"object\", \"required\": [\"repo\", \"branch_name\"], \"properties\": {\"repo\": {\"type\": \"string\", \"pattern\": \"^[a-zA-Z0-9._-]+/[a-zA-Z0-9._-]+$\", \"description\": \"Repository name in format \\\"owner/repo\\\"\"}, \"branch_name\": {\"type\": \"string\", \"pattern\": \"^[a-zA-Z0-9._/-]+$\", \"maxLength\": 255, \"minLength\": 1, \"description\": \"Name of the new branch to create\"}, \"source_branch\": {\"type\": \"string\", \"default\": \"main\", \"description\": \"Source branch, tag, or commit SHA to create the new branch from\"}}}','{}',NULL,'POST','{}','{}',1,1,'2025-08-05 01:06:47','2025-08-05 01:06:47','[\"github_token\"]','{}',NULL,'default',NULL),('761058de-7198-11f0-9aa8-f9c902b06a04','system','github_create_update_file','Create/Update GitHub File','github','Create or update a file in a GitHub repository','{\"type\": \"object\", \"required\": [\"repo\", \"path\", \"content\", \"message\"], \"properties\": {\"sha\": {\"type\": \"string\", \"description\": \"SHA of the file being replaced (required for updates, omit for new files)\"}, \"path\": {\"type\": \"string\", \"minLength\": 1, \"description\": \"Path to the file in the repository\"}, \"repo\": {\"type\": \"string\", \"pattern\": \"^[a-zA-Z0-9._-]+/[a-zA-Z0-9._-]+$\", \"description\": \"Repository name in format \\\"owner/repo\\\"\"}, \"branch\": {\"type\": \"string\", \"default\": \"main\", \"description\": \"Branch to commit to\"}, \"content\": {\"type\": \"string\", \"description\": \"File content (will be base64 encoded automatically)\"}, \"message\": {\"type\": \"string\", \"description\": \"Commit message for the file change\"}, \"committer\": {\"type\": \"object\", \"properties\": {\"name\": {\"type\": \"string\", \"description\": \"Committer name\"}, \"email\": {\"type\": \"string\", \"format\": \"email\", \"description\": \"Committer email address\"}}, \"description\": \"Committer information (optional)\"}}}','{}',NULL,'POST','{}','{}',1,1,'2025-08-05 01:06:47','2025-08-05 01:06:47','[\"github_token\"]','{}',NULL,'default',NULL),('func-github-read-code','system','github_read_code','GitHub Read Code','github','Read files and directory contents from a GitHub repository. IMPORTANT: Start by exploring the repository structure with path=\"\" (empty) to see available directories and files, then navigate to specific paths. Use this to access README files, source code, configuration files, or explore directory structures. Always check directory contents before trying to read specific files.','{\"type\": \"object\", \"required\": [\"owner\", \"repo\"], \"properties\": {\"ref\": {\"type\": \"string\", \"default\": \"\", \"description\": \"Branch, tag, or commit SHA. Examples: \\\"main\\\", \\\"develop\\\", \\\"v1.0.0\\\". Default is the default branch.\"}, \"path\": {\"type\": \"string\", \"default\": \"\", \"description\": \"File or directory path within the repo. EXPLORATION STRATEGY: 1) Start with \\\"\\\" (empty) to see root contents, 2) Navigate to directories like \\\"src/\\\", \\\"cmd/\\\", 3) Then read specific files. Examples: \\\"\\\" (root directory), \\\"src/\\\" (explore src directory), \\\"src/main.js\\\" (read specific file), \\\"README.md\\\" (read readme)\"}, \"repo\": {\"type\": \"string\", \"description\": \"Repository name (e.g., \\\"vscode\\\", \\\"react\\\", \\\"tensorflow\\\")\"}, \"owner\": {\"type\": \"string\", \"description\": \"GitHub username or organization name (e.g., \\\"microsoft\\\", \\\"facebook\\\", \\\"google\\\")\"}}}','{\"sha\": \"abc123\", \"name\": \"README.md\", \"path\": \"README.md\", \"size\": 1024, \"type\": \"file\", \"content\": \"IyBTYW1wbGUgUmVhZG1l\", \"encoding\": \"base64\", \"_metadata\": {\"source\": \"mock\"}}','https://api.github.com/repos/{owner}/{repo}/contents/{path}','GET','{\"Accept\": \"application/vnd.github.v3+json\", \"User-Agent\": \"GoGent-App\"}','{}',1,1,'2025-08-05 00:53:48','2025-08-05 01:05:36','[\"githubApiKey\"]','{\"githubApiKey\": {\"required\": true, \"description\": \"GitHub API token\"}}',NULL,'default','{\"sha\": \"abc123\", \"name\": \"README.md\", \"path\": \"README.md\", \"size\": 1024, \"type\": \"file\", \"content\": \"IyBTYW1wbGUgUmVhZG1l\", \"encoding\": \"base64\", \"_metadata\": {\"error\": \"GitHub API unavailable\", \"source\": \"fallback\"}}'),('func-github-read-issues','system','github_read_issues','GitHub Read Issues','github','Read and analyze issues from a GitHub repository. Use this to understand bugs, feature requests, development tasks, and project status. Great for getting insights into project challenges and roadmaps.','{\"type\": \"object\", \"required\": [\"owner\", \"repo\"], \"properties\": {\"repo\": {\"type\": \"string\", \"description\": \"Repository name (e.g., \\\"vscode\\\", \\\"react\\\", \\\"tensorflow\\\")\"}, \"sort\": {\"enum\": [\"created\", \"updated\", \"comments\"], \"type\": \"string\", \"default\": \"created\", \"description\": \"Sort criteria: \\\"created\\\" (newest first), \\\"updated\\\" (recently modified), \\\"comments\\\" (most discussed)\"}, \"owner\": {\"type\": \"string\", \"description\": \"GitHub username or organization name (e.g., \\\"microsoft\\\", \\\"facebook\\\", \\\"google\\\")\"}, \"state\": {\"enum\": [\"open\", \"closed\", \"all\"], \"type\": \"string\", \"default\": \"open\", \"description\": \"Filter by issue state: \\\"open\\\" (active issues), \\\"closed\\\" (resolved issues), \\\"all\\\" (everything)\"}, \"labels\": {\"type\": \"string\", \"description\": \"Filter by labels (comma-separated). Examples: \\\"bug\\\", \\\"enhancement\\\", \\\"bug,help-wanted\\\"\"}, \"creator\": {\"type\": \"string\", \"description\": \"Filter issues created by a specific user (username)\"}, \"assignee\": {\"type\": \"string\", \"description\": \"Filter issues assigned to a specific user (username)\"}, \"per_page\": {\"type\": \"integer\", \"default\": 30, \"maximum\": 100, \"minimum\": 1, \"description\": \"Number of issues to return (1-100). Default 30 is usually good for analysis.\"}, \"direction\": {\"enum\": [\"asc\", \"desc\"], \"type\": \"string\", \"default\": \"desc\", \"description\": \"Sort direction: \\\"desc\\\" (newest/highest first), \\\"asc\\\" (oldest/lowest first)\"}}}','{\"issues\": [{\"id\": 1, \"body\": \"This is a sample issue description for testing purposes\", \"user\": {\"login\": \"sample-user\"}, \"state\": \"open\", \"title\": \"Sample Issue\", \"labels\": [{\"name\": \"bug\", \"color\": \"f29513\"}], \"number\": 1, \"html_url\": \"https://github.com/owner/repo/issues/1\", \"assignees\": [], \"created_at\": \"2023-01-01T00:00:00Z\", \"updated_at\": \"2023-01-01T00:00:00Z\"}], \"status\": \"success\", \"total_count\": 1}','https://api.github.com/repos/{owner}/{repo}/issues','GET','{\"Accept\": \"application/vnd.github+json\", \"User-Agent\": \"GoGent-App\", \"X-GitHub-Api-Version\": \"2022-11-28\"}','{}',1,1,'2025-08-05 01:05:36','2025-08-05 01:05:36','[\"githubApiKey\"]','{\"githubApiKey\": {\"required\": true, \"description\": \"GitHub API token\"}}',NULL,'default','{\"issues\": [{\"id\": 0, \"body\": \"GitHub API is currently unavailable. This is mock fallback data.\", \"error\": \"API_UNAVAILABLE\", \"state\": \"open\", \"title\": \"Unable to fetch issues - GitHub API unavailable\", \"number\": 0